#' Estimate a restricted CIVAR model with Boswijk-Doornik iteration
#'
#' Solves for restricted adjustment and cointegration matrices in a CIVAR
#' system under linear restrictions on `alpha` and `beta`, using the iterative
#' procedure described by Boswijk and Doornik (2003).
#'
#' @param R0 Numeric matrix of dimension `T x n` containing residuals from the
#'   auxiliary regression of `dY_t` on `Z2_t`.
#' @param R1 Numeric matrix of dimension `T x n` containing residuals from the
#'   auxiliary regression of `Y_{t-1}` on `Z2_t`.
#' @param G Restriction matrix for `alpha`.
#' @param H Restriction matrix for `beta`.
#' @param h Restriction vector for `beta`, representing fixed components in the
#'   parametrization `vec(beta) = H phi + h`.
#' @param alpha Numeric `n x crk` matrix of initial values for the adjustment
#'   coefficients.
#' @param beta Numeric `n x crk` matrix of initial values for the cointegration
#'   vectors.
#' @param Omega Numeric `n x n` initial covariance matrix.
#' @param Y0 Numeric matrix of dimension `T x n` containing `dY_t`.
#' @param Z1 Numeric matrix containing lagged level regressors from the CIVAR
#'   representation.
#' @param Z2 Numeric matrix containing lagged stationary regressors and
#'   deterministic terms from the auxiliary regression.
#'
#' @details
#' The restriction system is written as
#' \deqn{vec(\alpha') = G \psi, \quad vec(\beta) = H \phi + h.}
#'
#' The routine alternates between updates of the free parameters in `alpha` and
#' `beta` and the innovation covariance matrix until the log-determinant of the
#' covariance matrix converges.
#'
#' @return A list containing the restricted regression object `VECMR`, its
#'   summary `VECMRS`, the restricted cointegration vectors `betar`, the
#'   restricted adjustment coefficients `alphar`, unrestricted short-run
#'   coefficients `LSKOEFR`, the likelihood-ratio statistic `LR`, and the final
#'   convergence error `error`.
#'
#' @export
#' @keywords internal
#'
ab_civar_test <- function(R0,R1,G,H,h,alpha,beta,Omega,Y0,Z1,Z2) {
  ### this function runs Doornik Boswijk Iteration to estimate restricted alpha and beta
  ### It also estimates the separate MRCIVAR and compare it with the restricted including the model with identical beta.
  ### Add output of of separate Models.
  n   = dim(alpha)[1]
  crk = dim(alpha)[2]
  T1 = nrow(R1)
  S00 <- crossprod(R0)/T1
  S01 <- crossprod(R0, R1)/T1
  S10 <- crossprod(R1, R0)/T1
  S11 <- crossprod(R1)/T1

  alphai = alpha
  betai = beta
  Omegai = Omega
  VS10 = S10
  dim(VS10) <- c(length(S10),1)
  error = 1
  tol   = 0.0000001
  vecpip = solve(S11)%*%S10;dim(vecpip) = c(length(vecpip),1)

  phii = solve(t(H)%*%kronecker(t(alphai)%*%solve(Omegai)%*%alphai,S11)%*%H)%*%
    (t(H)%*%kronecker(t(alphai)%*%solve(Omegai),diag(nrow(beta)))%*%VS10
     - t(H)%*%kronecker(t(alphai)%*%solve(Omegai)%*%alphai,S11)%*%h)

  betai <-H%*%phii+h ; dim(betai) <- c(nrow(beta),crk)

  gammai = solve(t(G)%*%kronecker(solve(Omegai),t(betai)%*%S11%*%betai)%*%G)%*%
    t(G)%*%kronecker(solve(Omegai),t(betai))%*%VS10

  talphai <- G%*%gammai;dim(talphai) <- c(crk,nrow(alpha))
  alphai = t(talphai)

  Omegai = S00 - alphai%*%t(betai)%*%S10-S01%*%betai%*%t(alphai)+alphai%*%t(betai)%*%S11%*%betai%*%t(alphai)


  while  ( error > tol ) {

    phir   = phii
    gammar = gammai
    Omegar = Omegai

    phii = solve(t(H)%*%kronecker(t(alphai)%*%solve(Omegai)%*%alphai,S11)%*%H)%*%
      (t(H)%*%kronecker(t(alphai)%*%solve(Omegai),diag(nrow(beta)))%*%VS10
       - t(H)%*%kronecker(t(alphai)%*%solve(Omegai)%*%alphai,S11)%*%h)

    betai <-H%*%phii+h ; dim(betai) <- c(nrow(beta),crk)

    gammai = solve(t(G)%*%kronecker(solve(Omegai),t(betai)%*%S11%*%betai)%*%G)%*%
      t(G)%*%kronecker(solve(Omegai),t(betai))%*%VS10

    talphai <- G%*%gammai;dim(talphai) <- c(crk,nrow(alpha))

    alphai = t(talphai)

    Omegai = S00 - alphai%*%t(betai)%*%S10-S01%*%betai%*%t(alphai)+alphai%*%t(betai)%*%S11%*%betai%*%t(alphai)
    error = max( abs(log(det(Omegai))-log(det(Omegar))) )

  }
  LR =  T1*(log(det(Omegar))-log(det(Omega)))


  CI = Z1%*%betai

  if ((crk>0)&(length(Z2)>0)) {
    VECMR<-stats::lm(Y0-Z1%*%betai%*%t(alphai)~0+Z2)
    VECMRS <- summary_civar(lm1=VECMR,sname ="Z2")
    LSKOEFR = VECMR$coefficients
  }
  if ((crk>0)&(length(Z2)==0)) {
    VECMR  <- NULL
    LSKOEFR =  NULL
  }
  if ((crk == 0)&(length(Z2)>0)) {
    VECMR <-stats::lm(Y0~0+Z2)
    LSKOEFR = VECMR$coefficients
  }
  if ((crk == 0)&(length(Z2)==0)) {
    VECMR<-NULL
    LSKOEFR<-NULL
  }

  result <- new.env()
  result$VECMR      = VECMR
  result$VECMRS     = VECMRS
  result$betar      = betai
  result$alphar     = alphai
  result$LSKOEFR    = LSKOEFR
  result$LR         = LR
  result$error      = error
  rr<-as.list(result)
  return(rr)
}



#' Test linear restrictions in a CIVAR model
#'
#' Applies likelihood-ratio testing for linear restrictions on the adjustment
#' and cointegration matrices of an estimated CIVAR object and returns the
#' restricted estimates.
#'
#' @param res Estimated CIVAR object to be tested.
#' @param H Restriction matrix for `beta`.
#' @param h Restriction vector for `beta` in `vec(beta) = H phi + h`.
#' @param phi Initial or user-supplied free-parameter vector for `beta`.
#' @param G Restriction matrix for `alpha`.
#' @param Dxflag Numeric flag indicating whether exogenous variables enter the
#'   cointegration space.
#'
#' @details
#' The tested restriction system is
#' \deqn{vec(\alpha') = G \psi, \quad vec(\beta) = H \phi + h.}
#'
#' When `Dxflag = 0`, the function works from the auxiliary objects produced by
#' `civar_estimate()`. When `Dxflag = 1`, it routes the problem through
#' `ab_l_rtest2()` for the specification in which exogenous variables enter the
#' long-run relation.
#'
#' @return A list containing the restricted CIVAR results, including the
#'   restricted VECM object, restricted `alpha` and `beta`, short-run
#'   coefficients, likelihood-ratio statistic, and convergence error.
#' @examples
#' X = matrix(stats::rnorm(2*207),207,2)
#' colnames(X) = c("ex1","ex2")
#' res_d  = civar_data(n=6,p=2,T=207,crk=2,type="exog1", X=as.matrix(X))
#' colnames(res_d$Y) =  c("w","p","U_l","r","yn","y")
#' res_e =  civar_estimate(res=res_d)
#' res_e$tst$erg
#' res_e$tst$beta
#' res_e$tst$VECMS
#' n = 6;  crk = 2
#' G = diag(n*crk); G0 = G; psi = matrix(1,n*crk,1); psi0=psi;   ### No restrictions on alpha
#' H = diag(n*crk); H2 = H[,-seq(1,n*crk,n)];
#' h2 = matrix(0,n*crk,1);
#' h2[seq(1,n*crk,n),1] = rep(1,crk);
#' phi2 = matrix(1,(n-1)*crk,1)                               ### no restrictions but normalization
#'
#' G0%*%psi0; H2%*%phi2+h2
#'
#' ABtest = civar_test(res=res_d,H=H2,h=h2,phi=phi2,G=G0,Dxflag=0)
#' ABtest$betar
#' ABtest$alphar
#' ABtest$VECMR$coefficients
#' ABtest$LR
#' #1-pchisq(ABtest$LR,2)   ### the fourth is the used restrictions
#'
#'
#' res_d  = civar_data(n=7,p=2,T=207,crk=2,type="const")
#' colnames(res_d$Y) =  c("w","p","U_l","r","yn","y","fsi")
#' res_e =  civar_estimate(res=res_d)
#' res_e$tst$erg
#' res_e$tst$beta
#' res_e$tst$VECMS
#'
#' n = 7;  crk = 2
#' G = diag(n*crk); G0 = G; psi = matrix(1,n*crk,1); psi0=psi;   ### No restrictions on alpha
#'
#' H = diag(n*crk); H2 = H[,-c(1,8)]; h2 = matrix(0,n*crk,1);
#' h2[c(1,8),1] = c(1,1);  phi2 = matrix(1,12,1)                 ### normalization
#'
#' G0%*%psi0; H2%*%phi2+h2
#'
#' ABtest = civar_test(res=res_d,H=H2,h=h2,phi=phi2,G=G0,Dxflag=1)
#' ABtest$LR
#' ABtest$betar
#' ABtest$alphar
#' #1-pchisq(ABtest$LR,4)
#'
#'
#' @export
civar_test <- function(res=res,H=H,h=h,phi=phi,G=G,Dxflag=0) {
###
### This function runs a likelihood ratio test of linear restrictions on alpha and beta in a CIVAR model
###
###             vec(alpha') = G psi , vec(beta) = H phi + h
###
###        example 1 (restrictions on alpha) test of exogeneity
###                  vec(alpha) is 45 x 1  vector  ( N = 9 crk = 5, defined by the model )
###                  G          is 45 x 40 matrix  ( the first variable is exogeneous, i.e. the 5 adjustment coefficient of the first variable are zero )
###                  psi        40 x 1 vector (free variaring parameters not appearing in the specification but implied by G)
###                  vec(beta)  is 45 x 1 vector   ( N = 0 crk = 5 )
###                  H          is 45 x 45 identity matrix
###                  phi        45 x 1 vector (free variaring parameters not appearing in the specification but implied by h =0
###                  h          45 x 1 zero matrix implying ver(beta) = phi  >> no restrictions on beta.
###                            (H is identity and h is zero vector implies only restrictions on alpha)
###
###        example 2 (restrictions on beta ) test of PPP
###                  vec(alpha) is 40 x 1  vector  ( N = 8 crk = 5 ) conditioal VECM  or VECMX model
###                  G          is 40 x 40 identity matrix, implying there is no restriction on alpha
###                  psi        40 x 1 vector (free variaring parameters not appearing in the specification but implied by the identity matrix G
###                  vec(beta)  is 45 x 1 vector   ( N = 8 crk = 5, defined by the model )
###                  H          is 45 x 2 matrix that picks out the elements under restricitons ( two colunms out of the identity matrix ) a zero row in H and the corresponding h implies zero-restrictions on beta.
###                             ones in a row of H and zero in the corresponding h implies non-restricted beta.
###                  phi        2  x 1  vector (free variaring parameters not appearing in the specification but implied by h =0
###                  h          45 x 1  non zero elements in this vector together with the zero elements in the corresponding row in H are the normalization conditions.
###                             (H is identity and h is zero vector implies only restrictions on alpha)
###
###
###
if (Dxflag==0) {
  res_e = civar_estimate(res=res)
  crk   = res_e$crk
  R0    = res_e$tst$R0
  R1    = res_e$tst$R1
  alpha = t(res_e$tst$estimation$coefficients[1:crk,])
  beta  = res_e$tst$beta
  Omega = res_e$tst$Omega
  Y0 = res_e$tst$Y0
  Z1 = res_e$tst$Z1
  Z2 = res_e$tst$Z2
  test <- ab_civar_test(R0,R1,G,H,h,alpha,beta,Omega,Y0,Z1,Z2)
}   else  {
y = res$Y
if (is.na(res$X)) x = 0 else x = res$X

if (res$type == "const") model = "III"
if (res$type == "none")  model = "I"
bnorm = "1"
type  = "eigen"
p     =  res$p
r     =  res$crk
### N = 7, crk = 5, alphe beta are N  x crk  = 7 x 5   H = 35x35 G 35x35
###  G = diag(35); h = matrix(0,35,1); h[c(1,8,15,22,29)] = c(1,1,1,1,1)  ; H = diag(35); H2 = H[,-c(1,8,15,22,29)]
test<-ab_l_rtest2(y,x,model = model, bnorm = bnorm,type = type,p = p, r=r, q = 0.95, H=H,h=h,G=G)
}
return(test)
}



#' Run restricted Johansen testing with linear constraints
#'
#' Performs Johansen-style cointegration testing and estimation under linear
#' restrictions on the cointegration vectors and adjustment coefficients, and
#' returns both unrestricted and restricted CIVAR quantities.
#'
#' @param y Numeric matrix of endogenous variables.
#' @param x Optional matrix of exogenous variables.
#' @param model Character string describing the deterministic specification.
#'   Supported values are `"I"`, `"II"`, `"III"`, `"IV"`, and `"V"`.
#' @param bnorm Character string specifying the normalization rule for the
#'   cointegration vectors. Supported values are `"1"` and `"2"`.
#' @param type Character string specifying whether the Johansen output is based
#'   on `"eigen"` or `"trace"` statistics.
#' @param p Integer lag order of the CIVAR model.
#' @param r Integer cointegration rank.
#' @param q Significance level used for the Johansen critical values. Supported
#'   values are `0.9`, `0.95`, and `0.99`.
#' @param H Restriction matrix for `beta`.
#' @param h Restriction vector for `beta`.
#' @param G Restriction matrix for `alpha`.
#'
#' @details
#' The restriction system is
#' \deqn{vec(\alpha') = G \psi, \quad vec(\beta) = H \phi + h.}
#'
#' The function first builds the Johansen regression objects implied by the
#' deterministic specification, computes the unrestricted cointegration
#' quantities, and then iterates to obtain restricted maximum-likelihood
#' estimates of `alpha` and `beta`.
#'
#' @return A list containing the Johansen test output, unrestricted VECM fit,
#'   restricted `alpha` and `beta`, short-run coefficients, likelihood-ratio
#'   statistic, and convergence error.
#' @export
#' @keywords internal
#'
ab_l_rtest2 =function (y,x,model = c("I","II","III","IV","V"), bnorm = c("1","2"),type = c("eigen", "trace"),p = 1, r = 2, q = 0.95, H=H,h=h,G=G)   {
###
### This function runs a likelihood ratio test of linear restrictions on alpha and beta in a CIVAR model
###
###		vec(alpha) = G psi , vec(beta) = H phi + h
###
###        example 1 (restrictions on alpha) test of exogeneity
###			   vec(alpha) is 45 x 1  vector  ( N = 9 crk = 5, defined by the model )
###                  G          is 45 x 40 matrix  ( the first variable is exogeneous, i.e. the 5 adjustment coefficient of the first variable are zero )
###		         psi        40 x 1 vector (free variaring parameters not appearing in the specification but implied by G)
###                  vec(beta)  is 45 x 1 vector   ( N = 0 crk = 5 )
###                  H          is 45 x 45 identity matrix
###                  phi        45 x 1 vector (free variaring parameters not appearing in the specification but implied by h =0
###                  h          45 x 1 zero matrix implying ver(beta) = phi  >> no restrictions on beta.
###			   (H is identity and h is zero vector implies only restrictions on alpha)
###
###        example 2 (restrictions on beta ) test of PPP
###  			   vec(alpha) is 40 x 1  vector  ( N = 8 crk = 5 ) conditioal VECM  or VECMX model
###                  G          is 40 x 40 identity matrix, implying there is no restriction on alpha
###		         psi        40 x 1 vector (free variaring parameters not appearing in the specification but implied by the identity matrix G
###                  vec(beta)  is 45 x 1 vector   ( N = 0 crk = 5, defined by the model )
###                  H          is 45 x 2 matrix that picks out the elements under restricitons ( two colunms out of the identity matrix ) a zero row in H and the corresponding h implies zero-restrictions on beta.
###                             ones in a row of H and zero in the corresponding h implies non-restricted beta.
###                  phi        2  x 1  vector (free variaring parameters not appearing in the specification but implied by h =0
###                  h          45 x 1  non zero elements in this vector together with the zero elements in the corresponding row in H are the normalization conditions.
###			   (H is identity and h is zero vector implies only restrictions on alpha)
###
###

    y <- as.matrix(y)
    model <- match.arg(model)
    type <- match.arg(type)
    #ret <- match.arg(ret)
    #ctable <- match.arg(ctable)
    if (q != 0.9 && q != 0.95 && q != 0.99) {
        return("please correct significance level")
    }
    ret = "statistics"

    p <- as.integer(p)
    N1 <- ncol(as.matrix(y))
    #N  <- ncol(as.matrix(y))
    if (N1<r) {
        return("y's dimension must be larger than r")
    }

    if  ( length(x) == 1 ) {  z <- y }
    else {
       z <- cbind(y,x)
    }

    M1 <- ncol(as.matrix(z))
    T <- nrow(as.matrix(z))
    ## Z <- embed(diff(z), p)
    Z <- embed_ts(diff(z), p)
    Y0 <- Z[, c(1:N1)]                # \Delta Y
    #X0 <- Z[,c((N1+1):M1)]           # \Delta X
    Z1 <- z[-T, ][p:(T - 1), ]        #      Z_1
    if ((p==1)&(length(x)==1)) {
       Z2 = NULL
       NOLAG = 1
    }
    else {
       Z2 <- Z[, c((N1+1):(M1*p))]       # \Delta Z_
    }
    T1 <- nrow(as.matrix(Y0))
    #lT = (1:T1)/(1:T1)
    lT = matrix(1,T1,1); colnames(lT) <- "Const"
    #Trend <- matrix((p + 1):TT, (TT - p), 1); colnames(Trend) <- "Trend"
    Trend <- matrix(1:T1, T1, 1); colnames(Trend) <- "Trend"
    if ( model == "I" ) {
    Y0 = Y0
    Z1 = Z1
    Z2 = Z2
    }
    if ( model == "II" ) {
    Y0 = Y0
    Z1 = cbind(lT,Z1)
    Z2 = Z2
    }
    if ( model == "III" ) {
    Y0 = Y0
    Z1 = Z1
    Z2 = cbind(Z2,lT)
    }
    if ( model == "IV" ) {
    Y0 = Y0
    Z1 = cbind(Trend,Z1)
    Z2 = cbind(Z2,lT)
    }
    if ( model == "V" ) {
    Y0 = Y0
    Z1 = cbind(Z1)
    Z2 = cbind(Z2,lT,Trend)
    }

    if (length(Z2)==0) {
        R0 <- Y0
        R1 <- Z1
    }
    else {

        M00 <- crossprod(Y0)/T1
        M11 <- crossprod(Z1)/T1
        M22 <- crossprod(Z2)/T1
        M01 <- crossprod(Y0, Z1)/T1
        M02 <- crossprod(Y0, Z2)/T1
        M10 <- crossprod(Z1, Y0)/T1
        M20 <- crossprod(Z2, Y0)/T1
        M12 <- crossprod(Z1, Z2)/T1
        M21 <- crossprod(Z2, Z1)/T1
        M22inv <- solve(M22)
        R0 <- Y0 - t(M02 %*% M22inv %*% t(Z2))
        R1 <- Z1 - t(M12 %*% M22inv %*% t(Z2))
    }
    S00 <- crossprod(R0)/T1
    S01 <- crossprod(R0, R1)/T1
    S10 <- crossprod(R1, R0)/T1
    S11 <- crossprod(R1)/T1
    Ctemp <- chol(S11, pivot = TRUE)
    pivot <- attr(Ctemp, "pivot")
    oo <- order(pivot)
    C <- t(Ctemp[, oo])
    Cinv <- solve(C)
    S00inv <- solve(S00)
    valeigen <- eigen(Cinv %*% S10 %*% S00inv %*% S01 %*% t(Cinv))

    #valeigen <- eigen(S11inv %*% S10 %*% S00inv %*% S01 )
    lambda <- valeigen$values
    e      <- valeigen$vector

    V <- t(Cinv) %*% e
    Vorg <- V
    V <- sapply(1:M1, function(j) V[, j]/V[1, j])
    W <- S01 %*% V %*% solve(t(V) %*% S11 %*% V)
    PI <- S01 %*% solve(S11)
    DELTA <- S00 - S01 %*% V %*% solve(t(V) %*% S11 %*% V) %*% t(V) %*% S10
    if (length(Z2)==0) {
       GAMMA = NULL
    }
    else {
       GAMMA <- M02 %*% M22inv - PI %*% M12 %*% M22inv
    }
    if (bnorm == "1") {
        beta   <- as.matrix(V[,1:r])
    }
    if (bnorm == "2") {
        beta = as.matrix(V[,1:r]%*%solve(V[1:r,1:r]))
    }

    if ((r>0)&(length(Z2)>0)) {
       CI = Z1%*%beta
       VECM<-stats::lm(Y0~0+CI+Z2)
       if (r==1)  { alpha = as.matrix(VECM$coefficients[1:1,]) }
       if (r > 1) { alpha = t(as.matrix(VECM$coefficients[1:r,])) }
       LSKOEF = stats::lm(Y0-Z1%*%beta%*%t(alpha)~0+Z2)$coefficients

    }
    if ((r>0)&(length(Z2)==0)) {
       CI = Z1%*%beta
       VECM<-stats::lm(Y0~0+CI)
       LSKOEF = NULL
    }
    if ((r == 0)&(length(Z2)>0)) {
       CI = 0
       VECM<-stats::lm(Y0~0+Z2)
       LSKOEF = stats::lm(Y0~0+Z2)$coefficients
    }
    if ((r == 0)&(length(Z2)==0)) {
       CI = 0
       VECM<-NULL
       LSKOEF = NULL
    }
    E = -T1 * log(1 - lambda)
    E = E[1:N1]
    LOGL = -T1/2.0*(log(det(S00))+sum(log((1-lambda)[1:r])))-T1*N1/2.0*log(2*pi)-T1*N1/2.0
    #LOGL = -T1/2.0*(log(det(S00))+sum(log((1-lambda)[1:N1])))-T1*N1/2.0*log(2*pi)-T1*N1/2.0

    Omega = 1.0/(nrow(VECM$residuals))*t(VECM$residuals)%*%VECM$residuals
    # T1*(log(det(Omega))-log(det(S00))-sum(log(1-lambda)[1:r]))   # correct

    ##### Estimation of VECM
    if (r==1)  { alpha = as.matrix(VECM$coefficients[1:1,]) }
    if (r > 1) { alpha = t(as.matrix(VECM$coefficients[1:r,])) }
    resultsvecm <- summary(VECM)

    if (model == "I") {
      Tab <- Tab1
    }
    if (model == "II") {
      Tab <- Tab2
    }
    if (model == "III") {
      Tab <- Tab3
    }
    if (model == "IV") {
      Tab <- Tab4
    }
    if (model == "V") {
      Tab <- Tab5
    }


    b = c(1:12)
    for (i in 1:12)   { b[i] = Tab[2*(i-1)+1,2+M1-N1] }
    a = c(1:12)
    for (i in 1:12)   { a[i] = Tab[2*i,2+M1-N1] }

    if (type == "eigen") {
        critical_vals = b
        M = matrix(0, N1, 1)
        j = 1
        rank = 0
        while (j <= N1 && E[j] > critical_vals[N1 + 1 - j]) {
            M[j, ] = M[j, ] + 1
            j = j + 1
            rank = rank + 1
        }
        if (ret == "test") {
            return(M)
        }
        erge <- cbind(E, critical_vals[N1:1])
        colnames(erge) <- c("teststatistic", "critical_value")

        if ( N1 > 1 ) {
           rownames(erge) <- c("r <= 0 |", paste("r <= ", 1:(N1 - 1),  " |", sep = ""))
        }
        if ( N1 == 1 ) {
           rownames(erge) <- c("r <= 0 |" )
        }

        coint_rank <- paste("Johansen-Test (with maximum-eigenvalue-teststatistic) indicates",
            rank, "cointegrating equation(s) at the", 1 - q,
            "level")
    }
    else {
        type = "trace"
